function data = mdp_TongVel(data, varargin)%MDP_TONGVEL  - MVIEW dataproc that computes combined velocity of all tongue transducers%% appends TONGVEL signal as DATA(end+1)%% by default applies to trajectories beginning with "T"% to use different names specify cellstr varargin as e.g. {'TB','JAW'}%% appends "TONGVEL" signal as DATA(end+1)%% usage examples: %% use default T* trajectories% mview(...,'DPROC','mdp_TongVel',...)%% use trajectory names "TB", "JAW"% mview(...,'DPROC',{{'mdp_TongVel',{'TB','JAW'}}}, ...)%% add TV trajectory w/o mview% data = mdp_TongVel(data)% mkt 11/01TVname = 'TONGVEL';if length(varargin) > 2,	% last arg is {pal,phar,labs}	traj = upper(varargin(1:end-1));	[~,tidx] = intersect({data.NAME},traj);else,	tn = char({data.NAME}');	tidx = find(tn(:,1) == 'T')';end;[nSamps,nComps] = size(data(tidx(1)).SIGNAL);if nComps > 3, nComps = 3; end;ts = NaN(nSamps, nComps, length(tidx));for ti = 1 : length(tidx), ts(:,:,ti) = data(tidx(ti)).SIGNAL(:,1:nComps); end;% make new signaldata(end+1) = data(tidx(1));data(end).NAME = TVname;ts = reshape(ts,nSamps,nComps*size(ts,3));dts = (ts(3:end,:) - ts(1:end-2,:)) ./ 2;dts(1,:) = (ts(2,:) - ts(1,:));dts(end,:) = (ts(end,:) - ts(end-1,:));data(end).SIGNAL = sqrt(sum(dts.^2,2));minS = min(data(end).SIGNAL);maxS = max(data(end).SIGNAL);spread = maxS - minS;data(end).SPREAD = [minS-spread*.1 maxS+spread*.1];data(end).NCOMPS = 1;